 * lines up with the rest of the viewport.
 */
function tryResolveFamilyInstancePanel(
  familyTypeId: string | undefined | null,
  cellPosition: THREE.Vector3,
  yaw: number,
  bimPickId: string,
  cellId: string,
  detailLevel?: ResolverDetailLevel,
): THREE.Group | null {
  if (!familyTypeId) return null;
